import { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import type { CSSProperties, MouseEvent as ReactMouseEvent, RefObject } from 'react';
import type { TimelineRow } from '@xzdarcy/timeline-engine';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';

interface OverlayEditorProps {
  rows: TimelineRow[];
  meta: Record<string, ClipMeta>;
  currentTime: number;
  playerContainerRef: RefObject<HTMLDivElement | null>;
  trackScaleMap: Record<string, number>;
  compositionWidth: number;
  compositionHeight: number;
  selectedClipId: string | null;
  onSelectClip: (clipId: string | null) => void;
  onOverlayChange: (actionId: string, patch: Partial<ClipMeta>) => void;
}

type DragMode = 'move' | 'resize-nw' | 'resize-ne' | 'resize-sw' | 'resize-se';
type OverlayBounds = { x: number; y: number; width: number; height: number };
type OverlayLayout = { left: number; top: number; width: number; height: number };

const MIN_CLIP_SIZE = 20;

function OverlayEditorComponent({
  rows,
  meta,
  currentTime,
  playerContainerRef,
  trackScaleMap,
  compositionWidth,
  compositionHeight,
  selectedClipId,
  onSelectClip,
  onOverlayChange,
}: OverlayEditorProps) {
  const [layout, setLayout] = useState<OverlayLayout | null>(null);
  const [editingClipId, setEditingClipId] = useState<string | null>(null);
  const [editText, setEditText] = useState('');
  const [dragOverride, setDragOverride] = useState<{ actionId: string; bounds: OverlayBounds } | null>(null);
  const dragState = useRef<{
    mode: DragMode;
    actionId: string;
    startMouseX: number;
    startMouseY: number;
    startBounds: OverlayBounds;
    latestBounds: OverlayBounds;
    hasChanges: boolean;
  } | null>(null);

  const getTrackDefaultBounds = useCallback((trackId: string): OverlayBounds => {
    const trackScale = Math.max(trackScaleMap[trackId] ?? 1, 0.01);
    return {
      x: Math.round(compositionWidth * (1 - trackScale) / 2),
      y: Math.round(compositionHeight * (1 - trackScale) / 2),
      width: Math.round(compositionWidth * trackScale),
      height: Math.round(compositionHeight * trackScale),
    };
  }, [compositionHeight, compositionWidth, trackScaleMap]);

  const getClipBounds = useCallback((clipMeta: ClipMeta, trackId: string): OverlayBounds => {
    if (clipMeta.clipType === 'text') {
      return {
        x: clipMeta.x ?? 0,
        y: clipMeta.y ?? 0,
        width: clipMeta.width ?? 640,
        height: clipMeta.height ?? 180,
      };
    }

    if (
      clipMeta.x !== undefined
      || clipMeta.y !== undefined
      || clipMeta.width !== undefined
      || clipMeta.height !== undefined
    ) {
      return {
        x: clipMeta.x ?? 0,
        y: clipMeta.y ?? 0,
        width: clipMeta.width ?? compositionWidth,
        height: clipMeta.height ?? compositionHeight,
      };
    }

    return getTrackDefaultBounds(trackId);
  }, [compositionHeight, compositionWidth, getTrackDefaultBounds]);

  const activeOverlays = useMemo(() => {
    const overlays: Array<{ actionId: string; track: string; label: string; bounds: OverlayBounds; isText: boolean }> = [];
    for (const row of rows) {
      if (!row.id.startsWith('V')) {
        continue;
      }

      for (const action of row.actions) {
        if (currentTime < action.start || currentTime >= action.end) {
          continue;
        }

        const clipMeta = meta[action.id];
        if (!clipMeta || clipMeta.track !== row.id) {
          continue;
        }

        const hasPositionOverride = clipMeta.clipType === 'text'
          || clipMeta.x !== undefined
          || clipMeta.y !== undefined
          || clipMeta.width !== undefined
          || clipMeta.height !== undefined;
        if (!hasPositionOverride && selectedClipId !== action.id) {
          continue;
        }

        overlays.push({
          actionId: action.id,
          track: row.id,
          label: clipMeta.text?.content || clipMeta.asset || action.id,
          bounds: getClipBounds(clipMeta, row.id),
          isText: clipMeta.clipType === 'text',
        });
      }
    }

    return overlays;
  }, [currentTime, getClipBounds, meta, rows, selectedClipId]);

  const effectiveOverlays = useMemo(() => {
    if (!dragOverride) {
      return activeOverlays;
    }

    return activeOverlays.map((overlay) => (
      overlay.actionId === dragOverride.actionId
        ? { ...overlay, bounds: dragOverride.bounds }
        : overlay
    ));
  }, [activeOverlays, dragOverride]);

  const computeLayout = useCallback((): OverlayLayout | null => {
    const player = playerContainerRef.current;
    if (!player || compositionWidth <= 0 || compositionHeight <= 0) {
      return null;
    }

    const parent = player.offsetParent as HTMLElement | null;
    if (!parent) {
      return null;
    }

    const playerRect = player.getBoundingClientRect();
    const parentRect = parent.getBoundingClientRect();
    const videoAspect = compositionWidth / compositionHeight;
    const containerAspect = playerRect.width / Math.max(1, playerRect.height);
    const videoWidth = containerAspect > videoAspect ? playerRect.height * videoAspect : playerRect.width;
    const videoHeight = containerAspect > videoAspect ? playerRect.height : playerRect.width / videoAspect;

    return {
      left: playerRect.left - parentRect.left + (playerRect.width - videoWidth) / 2,
      top: playerRect.top - parentRect.top + (playerRect.height - videoHeight) / 2,
      width: videoWidth,
      height: videoHeight,
    };
  }, [compositionHeight, compositionWidth, playerContainerRef]);

  useEffect(() => {
    const updateLayout = () => setLayout(computeLayout());

    updateLayout();
    window.addEventListener('resize', updateLayout);
    const player = playerContainerRef.current;
    const observer = typeof ResizeObserver !== 'undefined' && player ? new ResizeObserver(updateLayout) : null;
    if (observer && player) {
      observer.observe(player);
    }

    return () => {
      window.removeEventListener('resize', updateLayout);
      observer?.disconnect();
    };
  }, [computeLayout, playerContainerRef]);

  const commitDragChange = useCallback(() => {
    const state = dragState.current;
    dragState.current = null;
    setDragOverride(null);

    if (!state || !state.hasChanges) {
      return;
    }

    onOverlayChange(state.actionId, state.latestBounds);
  }, [onOverlayChange]);

  useEffect(() => {
    if (!dragState.current) {
      return;
    }

    const onMouseMove = (event: MouseEvent) => {
      const state = dragState.current;
      if (!state) {
        return;
      }

      const deltaX = event.clientX - state.startMouseX;
      const deltaY = event.clientY - state.startMouseY;
      const nextBounds = { ...state.startBounds };

      if (state.mode === 'move') {
        nextBounds.x += deltaX;
        nextBounds.y += deltaY;
      }
      if (state.mode.includes('e')) {
        nextBounds.width = Math.max(MIN_CLIP_SIZE, state.startBounds.width + deltaX);
      }
      if (state.mode.includes('s')) {
        nextBounds.height = Math.max(MIN_CLIP_SIZE, state.startBounds.height + deltaY);
      }
      if (state.mode.includes('w')) {
        nextBounds.x = state.startBounds.x + deltaX;
        nextBounds.width = Math.max(MIN_CLIP_SIZE, state.startBounds.width - deltaX);
      }
      if (state.mode.includes('n')) {
        nextBounds.y = state.startBounds.y + deltaY;
        nextBounds.height = Math.max(MIN_CLIP_SIZE, state.startBounds.height - deltaY);
      }

      state.latestBounds = nextBounds;
      state.hasChanges = true;
      setDragOverride({ actionId: state.actionId, bounds: nextBounds });
    };

    const onMouseUp = () => commitDragChange();

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };

import { memo, useCallback, useRef, useState, type MouseEvent as ReactMouseEvent } from 'react';
import { Download, Type, Video, Volume2, ZoomIn, ZoomOut } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/shared/components/ui/alert-dialog';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import { CompactPreview } from '@/tools/video-editor/components/CompactPreview';
import { PreviewPanel } from '@/tools/video-editor/components/PreviewPanel/PreviewPanel';
import { PropertiesPanel } from '@/tools/video-editor/components/PropertiesPanel/PropertiesPanel';
import { TimelineEditor } from '@/tools/video-editor/components/TimelineEditor/TimelineEditor';
import { useTimelineChromeContext } from '@/tools/video-editor/contexts/TimelineChromeContext';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { useTimelinePlaybackContext } from '@/tools/video-editor/contexts/TimelinePlaybackContext';
import { useKeyboardShortcuts } from '@/tools/video-editor/hooks/useKeyboardShortcuts';
import { useTimelineRealtime } from '@/tools/video-editor/hooks/useTimelineRealtime';

const MIN_TIMELINE_HEIGHT = 140;
const MIN_PREVIEW_HEIGHT = 180;
const STATUS_VARIANT = {
  saved: 'default',
  saving: 'secondary',
  dirty: 'outline',
  error: 'destructive',
} as const;

interface VideoEditorShellProps {
  mode: 'full' | 'compact';
  timelineId?: string | null;
  onCreateTimeline?: () => void;
}

function FullEditorLayout({ timelineId }: { timelineId: string }) {
  const editor = useTimelineEditorContext();
  const chrome = useTimelineChromeContext();
  const playback = useTimelinePlaybackContext();
  const navigate = useNavigate();
  const containerRef = useRef<HTMLDivElement>(null);
  const dividerRef = useRef<HTMLDivElement>(null);
  const [timelineHeight, setTimelineHeight] = useState<number | null>(null);
  const conflict = useTimelineRealtime({
    timelineId,
    saveStatus: chrome.saveStatus,
    onDiscardRemoteChanges: chrome.reloadFromServer,
  });

  useKeyboardShortcuts({
    hasSelectedClip: Boolean(editor.selectedClipId),
    moveSelectedClipToTrack: editor.moveSelectedClipToTrack,
    togglePlayPause: () => playback.previewRef.current?.togglePlayPause(),
    seekRelative: (deltaSeconds) => playback.previewRef.current?.seek(Math.max(0, playback.currentTime + deltaSeconds)),
    toggleMute: editor.handleToggleMute,
    splitSelectedClip: editor.handleSplitSelectedClip,
    deleteSelectedClip: () => {
      if (editor.selectedClipId) {
        editor.handleDeleteClip(editor.selectedClipId);
      }
    },
    clearSelection: () => editor.setSelectedClipId(null),
  });

  const onDividerMouseDown = useCallback((event: ReactMouseEvent) => {
    event.preventDefault();
    const container = containerRef.current;
    const divider = dividerRef.current;
    if (!container || !divider) {
      return;
    }

    divider.classList.add('is-dragging');
    document.body.style.cursor = 'row-resize';
    document.body.style.userSelect = 'none';

    const onMouseMove = (moveEvent: MouseEvent) => {
      const rect = container.getBoundingClientRect();
      const nextHeight = Math.max(MIN_TIMELINE_HEIGHT, rect.bottom - moveEvent.clientY);
      if (rect.height - nextHeight < MIN_PREVIEW_HEIGHT) {
        return;
      }
      container.style.gridTemplateRows = `minmax(0,1fr) auto ${nextHeight}px`;
    };

    const onMouseUp = () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
      divider.classList.remove('is-dragging');
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      const match = container.style.gridTemplateRows.match(/(\d+)px$/);
      container.style.gridTemplateRows = '';
      if (match) {
        setTimelineHeight(Number.parseInt(match[1], 10));
      }
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
  }, []);

  return (
    <>
      <div className="flex h-full min-h-0 flex-col overflow-hidden bg-background text-foreground">
        <div className="flex h-10 items-center gap-3 border-b border-border bg-background px-3 text-sm text-muted-foreground">
          <button
            type="button"
            className="shrink-0 transition-colors hover:text-foreground"
            onClick={() => navigate('/')}
          >
            ← Back
          </button>
          <div className="truncate text-foreground">{chrome.timelineName ?? 'Untitled timeline'}</div>
        </div>
        <main
          ref={containerRef}
          className="grid h-full min-h-0 flex-1 grid-cols-[minmax(0,1fr)_360px] gap-3 p-3"
          style={{ gridTemplateRows: timelineHeight ? `minmax(0,1fr) auto ${timelineHeight}px` : 'minmax(0,1fr) auto minmax(200px,36%)' }}
        >
          <div className="relative min-h-0">
            <div className="pointer-events-none absolute inset-x-0 top-0 z-20 flex items-center justify-between px-3 py-3">
              <div className="pointer-events-auto flex items-center gap-2">
                <Badge variant={STATUS_VARIANT[chrome.saveStatus]} className="h-5 px-1.5 text-[10px] capitalize">
                  {chrome.saveStatus}
                </Badge>
                <span className="font-mono text-[11px] tracking-[0.08em] text-muted-foreground">{playback.formatTime(playback.currentTime)}</span>
              </div>
              <div className="pointer-events-auto flex items-center gap-1">
                <Button type="button" size="icon" variant="ghost" className="h-7 w-7" onClick={chrome.handleAddText}>
                  <Type className="h-3.5 w-3.5" />
                </Button>
                <Button type="button" size="sm" className="h-7 gap-1.5 px-3 text-[11px]" onClick={() => void chrome.startRender()}>
                  <Download className="h-3.5 w-3.5" />
                  Render
                </Button>
              </div>
            </div>
            <PreviewPanel />
          </div>

          <div className="row-span-2 min-h-0 overflow-hidden">
            <PropertiesPanel />
          </div>

          <div
            ref={dividerRef}
            className="col-span-1 flex cursor-row-resize items-center justify-center rounded transition-colors hover:bg-accent/60"
            style={{ height: 10, marginBlock: -2 }}
            onMouseDown={onDividerMouseDown}
          >
            <div className="h-1 w-12 rounded-full bg-border" />
          </div>

          <div className="col-span-2 flex min-h-0 flex-col gap-2 overflow-hidden">
            <div className="flex items-center justify-between px-1">
              <div className="flex items-center gap-1">
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.handleAddTrack('visual')}>
                  <Video className="h-3.5 w-3.5" />
                </Button>
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.handleAddTrack('audio')}>
                  <Volume2 className="h-3.5 w-3.5" />
                </Button>
                {chrome.unusedTrackCount > 0 && (
                  <Button type="button" variant="ghost" size="sm" className="h-7 px-2 text-[11px]" onClick={chrome.handleClearUnusedTracks}>
                    Clear {chrome.unusedTrackCount} unused
                  </Button>
                )}
              </div>
              <div className="flex items-center gap-1">
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.setScaleWidth((value) => Math.max(value / 1.4, 40))}>
                  <ZoomOut className="h-3.5 w-3.5" />
                </Button>
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.setScaleWidth((value) => Math.min(value * 1.4, 500))}>
                  <ZoomIn className="h-3.5 w-3.5" />
                </Button>
              </div>
            </div>
            <div className="min-h-0 flex-1 overflow-hidden">
              <TimelineEditor />
            </div>
          </div>
        </main>
      </div>

      <AlertDialog open={conflict.isOpen} onOpenChange={conflict.setOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remote timeline changes detected</AlertDialogTitle>
            <AlertDialogDescription>
              Another tab updated this timeline while you still have unsaved local edits. Keep your local draft or discard it and reload the latest server version.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={conflict.keepLocalChanges}>Keep local draft</AlertDialogCancel>
            <AlertDialogAction onClick={() => void conflict.discardAndReload()}>Discard and reload</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

function VideoEditorShellComponent({ mode, timelineId, onCreateTimeline }: VideoEditorShellProps) {
  if (mode === 'compact') {
    return <CompactPreview timelineId={timelineId} onCreateTimeline={onCreateTimeline} />;
  }

  if (!timelineId) {
    return null;
  }

  return <FullEditorLayout timelineId={timelineId} />;
}

export const VideoEditorShell = memo(VideoEditorShellComponent);

