import { useMemo } from 'react';
import { ExternalLink, Plus } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { Button } from '@/shared/components/ui/button';
import { Slider } from '@/shared/components/ui/slider';
import { useTimelineChromeContext } from '@/tools/video-editor/contexts/TimelineChromeContext';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { useTimelinePlaybackContext } from '@/tools/video-editor/contexts/TimelinePlaybackContext';
import { RemotionPreview } from '@/tools/video-editor/components/PreviewPanel/RemotionPreview';
import { getTimelineDurationInFrames } from '@/tools/video-editor/lib/config-utils';

interface CompactPreviewProps {
  timelineId?: string | null;
  onCreateTimeline?: () => void;
}

export function CompactPreview({ timelineId, onCreateTimeline }: CompactPreviewProps) {
  const navigate = useNavigate();
  const { resolvedConfig } = useTimelineEditorContext();
  const { saveStatus } = useTimelineChromeContext();
  const { previewRef, playerContainerRef, currentTime, onPreviewTimeUpdate } = useTimelinePlaybackContext();

  const totalSeconds = useMemo(() => {
    if (!resolvedConfig) {
      return 1;
    }

    return getTimelineDurationInFrames(resolvedConfig, resolvedConfig.output.fps) / resolvedConfig.output.fps;
  }, [resolvedConfig]);

  if (!resolvedConfig || !timelineId) {
    return (
      <div className="flex h-full items-center justify-center bg-background">
        <div className="rounded-xl border border-dashed border-border bg-card/60 p-6 text-center">
          <div className="text-sm font-medium text-foreground">No active timeline</div>
          <div className="mt-1 text-xs text-muted-foreground">Create one in the full editor or open an existing timeline.</div>
          <div className="mt-4 flex justify-center gap-2">
            <Button type="button" size="sm" onClick={() => onCreateTimeline?.()}>
              <Plus className="mr-1 h-4 w-4" />
              Create timeline
            </Button>
            <Button type="button" size="sm" variant="outline" onClick={() => navigate('/tools/video-editor')}>
              Open editor
            </Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col bg-background">
      <div className="flex items-center justify-between border-b border-border px-3 py-2">
        <div>
          <div className="text-xs uppercase tracking-[0.16em] text-muted-foreground">Editor pane</div>
          <div className="text-sm text-foreground">Timeline {timelineId.slice(0, 8)} · {saveStatus}</div>
        </div>
        <Button type="button" size="sm" variant="outline" className="gap-1" onClick={() => navigate(`/tools/video-editor?timeline=${timelineId}`)}>
          <ExternalLink className="h-3.5 w-3.5" />
          Open in editor
        </Button>
      </div>
      <div className="min-h-0 flex-1 p-3">
        <div className="h-full overflow-hidden rounded-xl border border-border">
          <RemotionPreview
            ref={previewRef}
            config={resolvedConfig}
            compact
            onTimeUpdate={onPreviewTimeUpdate}
            playerContainerRef={playerContainerRef}
          />
        </div>
      </div>
      <div className="border-t border-border px-3 py-3">
        <Slider
          value={[currentTime]}
          min={0}
          max={Math.max(1, totalSeconds)}
          step={0.05}
          onValueChange={([value]) => previewRef.current?.seek(value)}
        />
      </div>
    </div>
  );
}

    };
  }, [commitDragChange, dragOverride]);

  const startDrag = useCallback((event: ReactMouseEvent, actionId: string, mode: DragMode, bounds: OverlayBounds) => {
    event.preventDefault();
    event.stopPropagation();
    onSelectClip(actionId);
    dragState.current = {
      mode,
      actionId,
      startMouseX: event.clientX,
      startMouseY: event.clientY,
      startBounds: bounds,
      latestBounds: bounds,
      hasChanges: false,
    };
  }, [onSelectClip]);

  const beginTextEdit = useCallback((actionId: string) => {
    const clipMeta = meta[actionId];
    if (clipMeta?.clipType !== 'text') {
      return;
    }

    setEditingClipId(actionId);
    setEditText(clipMeta.text?.content ?? '');
  }, [meta]);

  const commitText = useCallback(() => {
    if (!editingClipId) {
      return;
    }

    const clipMeta = meta[editingClipId];
    if (clipMeta?.clipType === 'text') {
      onOverlayChange(editingClipId, {
        text: {
          ...(clipMeta.text ?? { content: '' }),
          content: editText,
        },
      });
    }
    setEditingClipId(null);
  }, [editText, editingClipId, meta, onOverlayChange]);

  if (!layout) {
    return null;
  }

  const fontScale = layout.width / Math.max(1, compositionWidth);

  return (
    <div
      className="pointer-events-none absolute"
      style={{ left: layout.left, top: layout.top, width: layout.width, height: layout.height }}
    >
      {effectiveOverlays.map((overlay) => {
        const left = (overlay.bounds.x / compositionWidth) * layout.width;
        const top = (overlay.bounds.y / compositionHeight) * layout.height;
        const width = (overlay.bounds.width / compositionWidth) * layout.width;
        const height = (overlay.bounds.height / compositionHeight) * layout.height;
        const style: CSSProperties = { left, top, width, height };
        const isSelected = selectedClipId === overlay.actionId;
        const clipMeta = meta[overlay.actionId];
        const scaledFontSize = Math.max(12, (clipMeta?.text?.fontSize ?? 64) * fontScale);

        return (
          <div
            key={overlay.actionId}
            data-overlay-hit="true"
            className="absolute pointer-events-auto"
            style={style}
          >
            {editingClipId === overlay.actionId && overlay.isText ? (
              <textarea
                data-inline-text-editor="true"
                className="h-full w-full resize-none rounded border border-sky-400 bg-black/80 p-2 text-white outline-none"
                value={editText}
                style={{
                  fontSize: scaledFontSize,
                  color: clipMeta?.text?.color ?? '#ffffff',
                  textAlign: clipMeta?.text?.align ?? 'left',
                }}
                onChange={(event) => setEditText(event.target.value)}
                onBlur={commitText}
                onKeyDown={(event) => {
                  if ((event.metaKey || event.ctrlKey) && event.key === 'Enter') {
                    commitText();
                  }
                }}
                autoFocus
              />
            ) : (
              <button
                type="button"
                className={`group relative h-full w-full rounded border text-left transition ${isSelected ? 'border-sky-400 bg-sky-400/10 shadow-[0_0_0_1px_rgba(56,189,248,0.4)]' : 'border-white/30 bg-black/10 hover:border-white/60'}`}
                onMouseDown={(event) => startDrag(event, overlay.actionId, 'move', overlay.bounds)}
                onDoubleClick={() => beginTextEdit(overlay.actionId)}
                onClick={(event) => {
                  event.stopPropagation();
                  onSelectClip(overlay.actionId);
                }}
              >
                <span className="absolute left-1 top-1 rounded bg-black/70 px-1.5 py-0.5 text-[10px] text-white">
                  {overlay.label}
                </span>
                {(['resize-nw', 'resize-ne', 'resize-sw', 'resize-se'] as const).map((mode) => {
                  const position = {
                    'resize-nw': 'left-0 top-0 cursor-nwse-resize',
                    'resize-ne': 'right-0 top-0 cursor-nesw-resize',
                    'resize-sw': 'bottom-0 left-0 cursor-nesw-resize',
                    'resize-se': 'bottom-0 right-0 cursor-nwse-resize',
                  }[mode];
                  return (
                    <span
                      key={mode}
                      className={`absolute h-3 w-3 -translate-x-1/2 -translate-y-1/2 rounded-full border border-white/60 bg-sky-400 ${position}`}
                      onMouseDown={(event) => startDrag(event, overlay.actionId, mode, overlay.bounds)}
                    />
                  );
                })}
              </button>
            )}
          </div>
        );
      })}
    </div>
  );
}

