  const fit = track.fit ?? 'contain';
  if (fit === 'manual' || hasPositionOverride) {
    return {
      position: 'absolute',
      left: clip.x ?? 0,
      top: clip.y ?? 0,
      width: clip.width ?? compositionWidth,
      height: clip.height ?? compositionHeight,
      objectFit: 'cover',
      opacity: clip.opacity ?? 1,
    };
  }

  return {
    width: '100%',
    height: '100%',
    objectFit: fit,
    opacity: clip.opacity ?? 1,
  };
};

const VisualAsset: FC<VisualClipProps> = ({ clip, track, fps }) => {
  if (!clip.assetEntry) {
    return null;
  }

  const { width: compositionWidth, height: compositionHeight } = useVideoConfig();
  const style = getClipBoxStyle(clip, track, compositionWidth, compositionHeight);
  const sharedStyle: CSSProperties = {
    ...style,
    mixBlendMode: track.blendMode && track.blendMode !== 'normal' ? track.blendMode : undefined,
  };
  const clipVolume = clip.volume ?? 1;
  const isImage = clip.assetEntry.type?.startsWith('image');
  const isRendering = getRemotionEnvironment().isRendering;

  if (isImage) {
    return <Img src={clip.assetEntry.src} style={sharedStyle} crossOrigin="anonymous" />;
  }

  if (isRendering) {
    return (
      <OffthreadVideo
        src={clip.assetEntry.src}
        startFrom={secondsToFrames(clip.from ?? 0, fps)}
        playbackRate={clip.speed ?? 1}
        volume={clipVolume}
        muted={clipVolume <= 0}
        style={sharedStyle}
        transparent
        crossOrigin="anonymous"
      />
    );
  }

  return (
    <Video
      src={clip.assetEntry.src}
      startFrom={secondsToFrames(clip.from ?? 0, fps)}
      playbackRate={clip.speed ?? 1}
      volume={clipVolume}
      muted={clipVolume <= 0}
      style={sharedStyle}
      crossOrigin="anonymous"
    />
  );
};

export const VisualClip: FC<VisualClipProps> = ({ clip, track, fps }) => {
  const durationInFrames = getClipDurationInFrames(clip, fps);
  const frame = useCurrentFrame();
  const transitionRenderer = clip.transition ? transitions[clip.transition.type] : undefined;
  const transitionProgress = interpolate(
    frame,
    [0, Math.max(1, secondsToFrames(clip.transition?.duration ?? 0.4, fps))],
    [0, 1],
    {
      extrapolateLeft: 'clamp',
      extrapolateRight: 'clamp',
    },
  );
  const transitionStyle = transitionRenderer ? transitionRenderer(transitionProgress) : undefined;

  const content: ReactNode = (
    <AbsoluteFill style={{ overflow: 'hidden', ...transitionStyle }}>
      <VisualAsset clip={clip} track={track} fps={fps} />
    </AbsoluteFill>
  );

  return <>{wrapWithClipEffects(content, clip, durationInFrames, fps)}</>;
};

const LazyGuard: FC<{ durationInFrames: number; children: ReactNode }> = ({ durationInFrames, children }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const bufferFrames = Math.max(1, Math.round(fps));

  if (frame < -bufferFrames || frame > durationInFrames + bufferFrames) {
    return null;
  }

  return <>{children}</>;
};

export const VisualClipSequence: FC<VisualClipProps> = ({ clip, track, fps, predecessor }) => {
  const durationInFrames = getClipDurationInFrames(clip, fps);
  const transitionFrames = predecessor && clip.transition
    ? secondsToFrames(clip.transition.duration, fps)
    : 0;
  const from = Math.max(0, secondsToFrames(clip.at, fps) - transitionFrames);

  return (
    <Sequence key={clip.id} from={from} durationInFrames={durationInFrames}>
      <LazyGuard durationInFrames={durationInFrames}>
        <VisualClip clip={clip} track={track} fps={fps} predecessor={predecessor} />
      </LazyGuard>
    </Sequence>
  );
};

import { AbsoluteFill } from 'remotion';
import { memo, useMemo, type FC } from 'react';
import { getAudioTracks, getVisualTracks } from '@/tools/video-editor/lib/editor-utils';
import type { ResolvedTimelineClip, ResolvedTimelineConfig, TrackDefinition } from '@/tools/video-editor/types';
import { AudioTrack } from '@/tools/video-editor/compositions/AudioTrack';
import { TextClipSequence } from '@/tools/video-editor/compositions/TextClip';
import { VisualClipSequence } from '@/tools/video-editor/compositions/VisualClip';

const sortClipsByAt = (clips: ResolvedTimelineClip[]): ResolvedTimelineClip[] => {
  return [...clips].sort((left, right) => left.at - right.at);
};

const renderVisualTrack = (
  track: TrackDefinition,
  clips: ResolvedTimelineClip[],
  fps: number,
) => {
  const sortedClips = sortClipsByAt(clips);
  return (
    <AbsoluteFill
      key={track.id}
      style={{
        opacity: track.opacity ?? 1,
        mixBlendMode: track.blendMode && track.blendMode !== 'normal' ? track.blendMode : undefined,
      }}
    >
      {sortedClips.map((clip, index) => {
        if (clip.clipType === 'text') {
          return <TextClipSequence key={clip.id} clip={clip} track={track} fps={fps} />;
        }

        const predecessor = index > 0 ? sortedClips[index - 1] : null;
        const hasPositionOverride = (
          clip.x !== undefined
          || clip.y !== undefined
          || clip.width !== undefined
          || clip.height !== undefined
        );
        if (hasPositionOverride) {
          return (
            <VisualClipSequence
              key={clip.id}
              clip={clip}
              track={track}
              fps={fps}
              predecessor={predecessor}
            />
          );
        }

        return (
          <AbsoluteFill
            key={clip.id}
            style={{
              transform: `scale(${track.scale ?? 1})`,
              transformOrigin: 'center center',
              overflow: 'hidden',
            }}
          >
            <VisualClipSequence
              clip={clip}
              track={track}
              fps={fps}
              predecessor={predecessor}
            />
          </AbsoluteFill>
        );
      })}
    </AbsoluteFill>
  );
};

export const TimelineRenderer: FC<{ config: ResolvedTimelineConfig }> = memo(({ config }) => {
  const fps = config.output.fps;
  const visualTracks = useMemo(() => [...getVisualTracks(config)].reverse(), [config]);
  const audioTracks = useMemo(() => getAudioTracks(config), [config]);
  const clipsByTrack = useMemo(() => {
    return config.clips.reduce<Record<string, ResolvedTimelineClip[]>>((groups, clip) => {
      groups[clip.track] ??= [];
      groups[clip.track].push(clip);
      return groups;
    }, {});
  }, [config]);

  return (
    <AbsoluteFill style={{ backgroundColor: 'black', overflow: 'hidden' }}>
      <AbsoluteFill style={{ justifyContent: 'center', alignItems: 'center' }}>
        <AbsoluteFill style={{ position: 'relative', overflow: 'hidden' }}>
          {visualTracks.map((track) => {
            const trackClips = clipsByTrack[track.id] ?? [];
            return renderVisualTrack(track, trackClips, fps);
          })}
        </AbsoluteFill>
      </AbsoluteFill>
      {audioTracks.map((track) => (
        <AudioTrack
          key={track.id}
          trackId={track.id}
          clips={clipsByTrack[track.id] ?? []}
          fps={fps}
        />
      ))}
    </AbsoluteFill>
  );
});

