import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import type { Database } from '@/integrations/supabase/databasePublicTypes';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { uploadImageToStorage } from '@/shared/lib/media/imageUploader';
import {
  generateClientThumbnail,
  uploadImageWithThumbnail,
} from '@/shared/media/clientThumbnailGenerator';
import { cropImageToProjectAspectRatio } from '@/shared/lib/media/imageCropper';
import { parseRatio } from '@/shared/lib/media/aspectRatios';
import { VARIANT_TYPE } from '@/shared/constants/variantTypes';

export interface ExternalImageDropVariables {
  imageFiles: File[];
  targetShotId: string | null;
  currentProjectQueryKey: string | null;
  currentShotCount: number;
  skipAutoPosition?: boolean;
  positions?: number[];
  onProgress?: (fileIndex: number, fileProgress: number, overallProgress: number) => void;
  skipOptimistic?: boolean;
}

interface CropConfig {
  shouldCrop: boolean;
  targetAspectRatio: number | null;
  aspectRatioSource: 'none' | 'shot' | 'project';
}

interface ProcessDroppedImagesInput {
  variables: ExternalImageDropVariables;
  projectId: string;
  createShot: (input: {
    name: string;
    projectId: string;
    shouldSelectAfterCreation: boolean;
  }) => Promise<{ shot?: { id?: string } } | null | undefined>;
  addImageToShot: (input: {
    shot_id: string;
    generation_id: string;
    project_id: string;
    imageUrl?: string;
    thumbUrl?: string;
    timelineFrame?: number;
    skipOptimistic?: boolean;
  }) => Promise<unknown>;
  addImageToShotWithoutPosition: (input: {
    shot_id: string;
    generation_id: string;
    project_id: string;
    imageUrl?: string;
    thumbUrl?: string;
  }) => Promise<unknown>;
  createGeneration?: typeof createGenerationForUploadedImage;
}

const buildProgressHandler = (
  onProgress: ExternalImageDropVariables['onProgress'],
  fileIndex: number,
  totalFiles: number,
) =>
  onProgress
    ? (progress: number) => {
        const overallProgress = Math.round(((fileIndex + progress / 100) / totalFiles) * 100);
        onProgress(fileIndex, progress, overallProgress);
      }
    : undefined;

const createGenerationForUploadedImage = async (
  imageUrl: string,
  fileName: string,
  fileType: string,
  fileSize: number,
  projectId: string,
  thumbnailUrl?: string,
): Promise<Database['public']['Tables']['generations']['Row']> => {
  const generationParams = {
    source: 'upload',
    original_filename: fileName,
    file_type: fileType,
    file_size: fileSize,
  };

  const { data, error } = await supabase().from('generations')
    .insert({
      project_id: projectId,
      type: 'image',
      location: imageUrl,
      thumbnail_url: thumbnailUrl || imageUrl,
      params: generationParams,
    })
    .select()
    .single();

  if (error) {
    throw error;
  }

  await supabase().from('generation_variants').insert({
    generation_id: data.id,
    location: imageUrl,
    thumbnail_url: thumbnailUrl || imageUrl,
    is_primary: true,
    variant_type: VARIANT_TYPE.ORIGINAL,
    name: 'Original',
    params: generationParams,
  });

  return data;
};

async function getCropConfig(projectId: string, shotId: string | null): Promise<CropConfig> {
  const config: CropConfig = {
    shouldCrop: true,
    targetAspectRatio: null,
    aspectRatioSource: 'none',
  };

  try {
    const { data: projectData } = await supabase().from('projects')
      .select('aspect_ratio, settings')
      .eq('id', projectId)
      .single();

    let shotAspectRatio: string | null = null;
    if (shotId) {
      const { data: shotData } = await supabase().from('shots')
        .select('aspect_ratio')
        .eq('id', shotId)
        .single();
      shotAspectRatio = shotData?.aspect_ratio || null;
    }

    const uploadSettings = (projectData?.settings as Record<string, unknown> | null)?.upload as Record<string, unknown> | undefined;
    const cropToProjectSize = uploadSettings?.cropToProjectSize;
    config.shouldCrop = typeof cropToProjectSize === 'boolean' ? cropToProjectSize : true;

    const effectiveRatioStr = shotAspectRatio || projectData?.aspect_ratio || null;
    if (effectiveRatioStr) {
      config.targetAspectRatio = parseRatio(effectiveRatioStr);
      config.aspectRatioSource = shotAspectRatio ? 'shot' : 'project';
    }
  } catch (error) {
    normalizeAndPresentError(error, { context: 'useShotCreation:aspectRatio', showToast: false });
  }

  return config;
}

async function cropFilesIfNeeded(imageFiles: File[], config: CropConfig): Promise<File[]> {
  const { shouldCrop, targetAspectRatio } = config;
  if (!shouldCrop || !targetAspectRatio || Number.isNaN(targetAspectRatio)) {
    return imageFiles;
  }

  try {
    const cropPromises = imageFiles.map(async (file) => {
      try {
        if (!file.type.startsWith('image/')) {
          return file;
        }

        const result = await cropImageToProjectAspectRatio(file, targetAspectRatio);
        return result?.croppedFile || file;
      } catch (error) {
        normalizeAndPresentError(error, { context: `useShotCreation:crop:${file.name}`, showToast: false });
        return file;
      }
    });

    return await Promise.all(cropPromises);
  } catch (error) {
    normalizeAndPresentError(error, { context: 'useShotCreation:batchCrop', showToast: false });
    return imageFiles;
  }
}

async function ensureTargetShotId(
  targetShotId: string | null,
  currentShotCount: number,
  projectId: string,
  createShot: ProcessDroppedImagesInput['createShot'],
): Promise<string | null> {
  if (targetShotId) {
    return targetShotId;
  }

  const newShotName = `Shot ${currentShotCount + 1}`;
  const result = await createShot({
    name: newShotName,
    projectId,
    shouldSelectAfterCreation: true,
  });

  if (!result?.shot?.id) {
    toast.error('Failed to create new shot.');
    return null;
  }

  return result.shot.id;
}

async function uploadImageWithFallback(
  imageFile: File,
  fileIndex: number,
  totalFiles: number,
  onProgress?: ExternalImageDropVariables['onProgress'],
): Promise<{ imageUrl: string; thumbnailUrl: string }> {
  const progressHandler = buildProgressHandler(onProgress, fileIndex, totalFiles);
  let imageUrl = '';
  let thumbnailUrl = '';

  try {
    const thumbnailResult = await generateClientThumbnail(imageFile, 300, 0.8);
    const uploadResult = await uploadImageWithThumbnail(
      imageFile,
      thumbnailResult.thumbnailBlob,
      { onProgress: progressHandler },
    );
    imageUrl = uploadResult.imageUrl;
    thumbnailUrl = uploadResult.thumbnailUrl;
  } catch (error) {
    normalizeAndPresentError(error, { context: `useShotCreation:thumbnail:${imageFile.name}`, showToast: false });
    imageUrl = await uploadImageToStorage(imageFile, 3, progressHandler);
    thumbnailUrl = imageUrl;
  }

  return { imageUrl, thumbnailUrl };
}

async function attachGenerationToShot(input: {
  shotId: string;
  generation: Database['public']['Tables']['generations']['Row'];
  projectId: string;
  thumbnailUrl: string;
  fileIndex: number;
  variables: ExternalImageDropVariables;
  addImageToShot: ProcessDroppedImagesInput['addImageToShot'];
  addImageToShotWithoutPosition: ProcessDroppedImagesInput['addImageToShotWithoutPosition'];

  addImageToShotWithoutPosition: ProcessDroppedImagesInput['addImageToShotWithoutPosition'];
}): Promise<void> {
  const {
    shotId,
    generation,
    projectId,
    thumbnailUrl,
    fileIndex,
    variables,
    addImageToShot,
    addImageToShotWithoutPosition,
  } = input;

  const { positions, skipAutoPosition, skipOptimistic } = variables;
  const explicitPosition = positions && positions.length > fileIndex ? positions[fileIndex] : undefined;
  const baseInput = {
    shot_id: shotId,
    generation_id: generation.id as string,
    project_id: projectId,
    imageUrl: generation.location || undefined,
    thumbUrl: thumbnailUrl || generation.location || undefined,
  };

  if (explicitPosition !== undefined) {
    await addImageToShot({
      ...baseInput,
      timelineFrame: explicitPosition,
      skipOptimistic,
    });
    return;
  }

  if (skipAutoPosition) {
    await addImageToShotWithoutPosition(baseInput);
    return;
  }

  await addImageToShot({
    ...baseInput,
    skipOptimistic,
  });
}

async function processSingleDroppedImage(input: {
  imageFile: File;
  fileIndex: number;
  totalFiles: number;
  shotId: string;
  projectId: string;
  variables: ExternalImageDropVariables;
  addImageToShot: ProcessDroppedImagesInput['addImageToShot'];
  addImageToShotWithoutPosition: ProcessDroppedImagesInput['addImageToShotWithoutPosition'];
  createGeneration: typeof createGenerationForUploadedImage;
}): Promise<string | null> {
  const {
    imageFile,
    fileIndex,
    totalFiles,
    shotId,
    projectId,
    variables,
    addImageToShot,
    addImageToShotWithoutPosition,
    createGeneration,
  } = input;

  const { imageUrl, thumbnailUrl } = await uploadImageWithFallback(
    imageFile,
    fileIndex,
    totalFiles,
    variables.onProgress,
  );

  if (!imageUrl) {
    toast.error(`Failed to upload image ${imageFile.name} to storage.`);
    return null;
  }

  let generation: Database['public']['Tables']['generations']['Row'];
  try {
    generation = await createGeneration(
      imageUrl,
      imageFile.name,
      imageFile.type,
      imageFile.size,
      projectId,
      thumbnailUrl,
    );
  } catch (error) {
    toast.error(`Failed to create generation data for ${imageFile.name}: ${(error as Error).message}`);
    return null;
  }

  if (!generation?.id) {
    toast.error(`Failed to create generation record for ${imageFile.name}.`);
    return null;
  }

  await attachGenerationToShot({
    shotId,
    generation,
    projectId,
    thumbnailUrl,
    fileIndex,
    variables,
    addImageToShot,
    addImageToShotWithoutPosition,
  });

  return generation.id as string;
}

export async function processDroppedImages(
  input: ProcessDroppedImagesInput,
): Promise<{ shotId: string; generationIds: string[] } | null> {
  const {
    variables,
    projectId,
    createShot,
    addImageToShot,
    addImageToShotWithoutPosition,
    createGeneration = createGenerationForUploadedImage,
  } = input;
  const { imageFiles, targetShotId, currentShotCount } = variables;

  const cropConfig = await getCropConfig(projectId, targetShotId);
  const processedFiles = await cropFilesIfNeeded(imageFiles, cropConfig);
  const shotId = await ensureTargetShotId(targetShotId, currentShotCount, projectId, createShot);
  if (!shotId) {
    return null;
  }

  const generationIds: string[] = [];
  for (let fileIndex = 0; fileIndex < processedFiles.length; fileIndex++) {
    const imageFile = processedFiles[fileIndex];
    try {
      const generationId = await processSingleDroppedImage({
        imageFile,
        fileIndex,
        totalFiles: processedFiles.length,
        shotId,
        projectId,
        variables,
        addImageToShot,
        addImageToShotWithoutPosition,
        createGeneration,
      });
      if (generationId) {
        generationIds.push(generationId);
      }
    } catch (error) {
      normalizeAndPresentError(error, { context: 'useShotCreation', toastTitle: `Failed to process file ${imageFile.name}` });
    }
  }

  return generationIds.length > 0 ? { shotId, generationIds } : null;
}

/**
 * Generation Mutations
 * ====================
 *
 * Mutation hooks for creating, updating, deleting, and starring generations.
 * Extracted from useProjectGenerations.ts to separate query and mutation concerns.
 *
 * ## Exports
 * - `useDeleteGeneration` — Delete a generation
 * - `useDeleteVariant` — Delete a variant from generation_variants
 * - `useUpdateGenerationLocation` — Update a generation's location/thumbnail
 * - `useCreateGeneration` — Create a new generation (external upload)
 * - `useToggleGenerationStar` — Star/unstar with optimistic updates
 *
 * @module useGenerationMutations
 */

import { useMutation, useQueryClient } from '@tanstack/react-query';
import type { Json } from '@/integrations/supabase/jsonTypes';
import {
  createExternalUploadGeneration,
  deleteGenerationInProject,
  deleteVariantInProject,
  updateGenerationLocationInProject,
  updateGenerationStarInProject,
  type ExternalUploadGenerationParams,
} from '@/integrations/supabase/repositories/generationMutationsRepository';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { dispatchAppEvent } from '@/shared/lib/typedEvents';
import {
  applyOptimisticGenerationStarUpdate,
  rollbackOptimisticGenerationStarUpdate,
} from '@/shared/hooks/invalidation/generationStarCacheCoordinator';
import type { GenerationRow } from '@/domains/generation/types';
import { coerceGenerationRowDto, mapGenerationRowDtoToRow } from '@/domains/generation/mappers/generationRowMapper';

// ===== Helper Functions (internal) =====

interface ScopedGenerationInput {
  id: string;
  projectId: string;
}

interface ScopedVariantInput {
  id: string;
  projectId: string;
}

interface CreateGenerationInput {
  imageUrl: string;
  fileName: string;
  fileType: string;
  fileSize: number;
  projectId: string;
  prompt: string;
  thumbnailUrl?: string;
  resolution?: string;
  aspectRatio?: string;
}

function buildExternalUploadGenerationParams(input: CreateGenerationInput): ExternalUploadGenerationParams {
  return {
    prompt: input.prompt,
    extra: {
      source: 'external_upload',
      original_filename: input.fileName,
      file_type: input.fileType,
      file_size: input.fileSize,
    },
    ...(input.resolution ? { resolution: input.resolution } : {}),
    ...(input.aspectRatio ? { aspect_ratio: input.aspectRatio } : {}),
  };
}

/**
 * Update generation location via the scoped repository adapter.
 * @internal Used by useUpdateGenerationLocation hook.
 */
async function updateGenerationLocation(
  params: ScopedGenerationInput & { location: string; thumbnailUrl?: string },
): Promise<void> {
  await updateGenerationLocationInProject({
    id: params.id,
    projectId: params.projectId,
    location: params.location,
    thumbnailUrl: params.thumbnailUrl,
  });
}

/**
 * Create a new generation via the repository boundary.
 * @internal Used by useCreateGeneration hook.
 */
async function createGeneration(params: CreateGenerationInput): Promise<GenerationRow> {
  const generationParams = buildExternalUploadGenerationParams(params);

  const data = await createExternalUploadGeneration({
    imageUrl: params.imageUrl,
    thumbnailUrl: params.thumbnailUrl || params.imageUrl,
    fileType: params.fileType || 'image',
    projectId: params.projectId,
    generationParams,
  });

  const row = coerceGenerationRowDto(data as Json | Record<string, unknown>);
  if (!row) {
    throw new Error('Created generation row has unexpected shape');
  }
  return mapGenerationRowDtoToRow(row);
}

/**
 * Star/unstar a generation via the scoped repository adapter.
 * @internal Used by useToggleGenerationStar hook.
 */
async function toggleGenerationStar(params: ScopedGenerationInput & { starred: boolean }): Promise<void> {
  await updateGenerationStarInProject(params);
}

// ===== Mutation Hooks =====

/**
 * Delete a generation with project-scoped verification.
 */
async function deleteGenerationScoped(input: ScopedGenerationInput): Promise<void> {
  await deleteGenerationInProject(input);
}

/**
 * Delete a variant with project-scoped verification via its parent generation.
 */
async function deleteVariantScoped(input: ScopedVariantInput): Promise<void> {
  await deleteVariantInProject(input);
}

export function useDeleteGeneration() {
  return useMutation({
    mutationFn: deleteGenerationScoped,
    onError: (error: Error) => {
      normalizeAndPresentError(error, {
        context: 'useDeleteGeneration',
        toastTitle: 'Failed to delete generation',
      });
    },
  });
}

/**
 * Delete a variant from generation_variants table.
 * Use this for edit tools (edit-images, edit-video, character-animate) that create variants.
 */
export function useDeleteVariant() {
  return useMutation({
    mutationFn: deleteVariantScoped,
    onError: (error: Error) => {
      normalizeAndPresentError(error, {
        context: 'useDeleteVariant',
        toastTitle: 'Failed to delete variant',
      });
    },
  });
}

export function useUpdateGenerationLocation() {
  return useMutation({
    mutationFn: ({ id, location, thumbnailUrl, projectId }: {
      id: string;
      location: string;
      thumbnailUrl?: string;
      projectId: string;
    }) => {
      return updateGenerationLocation({ id, location, thumbnailUrl, projectId });
    },
    onError: (error: Error) => {
      normalizeAndPresentError(error, { context: 'useUpdateGenerationLocation', toastTitle: 'Failed to update generation' });
    },
  });
}

export function useCreateGeneration() {
  return useMutation({
    mutationFn: createGeneration,
    onError: (error: Error) => {
      normalizeAndPresentError(error, { context: 'useCreateGeneration', toastTitle: 'Failed to create generation' });
    },
  });
}

export function useToggleGenerationStar() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ id, starred, projectId }: { id: string; starred: boolean; projectId: string; shotId?: string }) => {
      return toggleGenerationStar({ id, starred, projectId });
    },
    onMutate: async ({ id, starred, shotId }) => {
      return applyOptimisticGenerationStarUpdate(queryClient, {
        generationId: id,
        starred,
        shotId,
      });
    },
    onError: (error: Error, _variables, context) => {
      rollbackOptimisticGenerationStarUpdate(queryClient, context);
      normalizeAndPresentError(error, { context: 'useToggleGenerationStar', toastTitle: 'Failed to toggle star' });
    },
    onSuccess: (_data, variables) => {
      // Emit custom event so Timeline knows to refetch star data
      if (variables.shotId) {
        dispatchAppEvent('generation-star-updated', {
          generationId: variables.id, shotId: variables.shotId!, starred: variables.starred,
        });
      }
    },
  });
}

import { getSupabaseClient } from '@/integrations/supabase/client';
import type { Json } from '@/integrations/supabase/jsonTypes';
import type { PersistedGenerationParams } from '@/domains/generation/types/generationParams';
import type { GenerationRowDto } from '@/domains/generation/types/generationRowDto';
import { VARIANT_TYPE } from '@/shared/constants/variantTypes';
import {
  resolveGenerationProjectScope,
  resolveVariantProjectScope,
} from '@/shared/lib/tasks/generationTaskRepository';

interface ProjectScopedGenerationInput {
  id: string;
  projectId: string;
}

export interface ExternalUploadGenerationParams extends PersistedGenerationParams {
  prompt: string;
  extra: {
    source: 'external_upload';
    original_filename: string;
    file_type: string;
    file_size: number;
  };
}

interface CreateExternalUploadGenerationInput {
  imageUrl: string;
  thumbnailUrl: string;
  fileType: string;
  projectId: string;
  generationParams: ExternalUploadGenerationParams;
}

type ScopedMutationRowsResult<Row extends { id: string }> = Promise<{
  data: Row[] | null;
  error: unknown;
}>;

function requireProjectScope(projectId: string): string {
  if (projectId.trim().length > 0) {
    return projectId;
  }

  throw new Error('Mutation requires project scope');
}

function throwScopedMutationFailure(error: unknown, emptyMessage: string): never {
  if (error instanceof Error) {
    throw error;
  }
  if (
    error &&
    typeof error === 'object' &&
    'message' in error &&
    typeof (error as { message?: unknown }).message === 'string'
  ) {
    throw new Error((error as { message: string }).message);
  }
  throw new Error(emptyMessage);
}

async function assertGenerationProjectScope(
  generationId: string,
  projectId: string,
): Promise<string> {
  const scope = await resolveGenerationProjectScope(generationId, projectId);
  if (scope.status === 'ok') {
    return projectId;
  }

  throw new Error(`Generation scope validation failed (${scope.status})`);
}

async function resolveScopedVariantGenerationId(
  variantId: string,
  projectId: string,
): Promise<string> {
  const scope = await resolveVariantProjectScope(variantId, projectId);
  if (scope.status === 'ok' && scope.generationId) {
    return scope.generationId;
  }

  throw new Error(`Variant scope validation failed (${scope.status})`);
}

async function requireScopedRows<Row extends { id: string }>(
  resultPromise: ScopedMutationRowsResult<Row>,
  emptyMessage: string,
): Promise<Row[]> {
  const result = await resultPromise;
  if (result.error) {
    throwScopedMutationFailure(result.error, emptyMessage);
  }
  if (!result.data || result.data.length === 0) {
    throw new Error(emptyMessage);
  }
  return result.data;
}

